export interface HarmonyTransitiveAuth {
    /**
     * Request a Transitive Auth token for the current Midway-authenticated user. If provided, a token with the specified LOB expression will be requested.
     * Harmony acts as an "initiator" and requests the token from the TransitiveAuthIssuerService.
     *
     * The TA token is valid for 5 minutes and is not reusable. {@link https://w.amazon.com/bin/view/IdentityServices/Transitive_Authentication/Onboarding/TokenPropagationOnboarding#HTAtokenpropagationrequirements Include it in the `x-amzn-transitive-authentication-token` header} in backend calls.
     *
     * This method requires {@link https://console.harmony.a2z.com/docs/api-reference.html#TransitiveAuth%20Service onboarding with the Harmony team} before it's accessible to your application.
     *
     * @example
     * window.harmony.transitiveAuth.getTATokenForMidway().then(token => {
     *   // Use the token
     *   fetch("https://my-api-example.amazon.com", { headers: { 'x-amzn-transitive-authentication-token': token }});
     * })
     *
     * @example
     * window.harmony.transitiveAuth.getTATokenForMidway("0").then(token => {
     *   // Use the token
     *   fetch("https://my-api-example.amazon.com", { headers: { 'x-amzn-transitive-authentication-token': token }});
     * })
     *
     * @example
     * window.harmony.transitiveAuth.getTATokenForMidway("foo")
     *   .then(token => {
     *     // You won't get here since "foo" isn't a valid LOB expression.
     *   })
     *   .catch(error => {
     *     // Example error
     *     // {
     *     //   "name": "CoralServiceError",
     *     //   "message": "Input LOB expression: foo is invalid.",
     *     //   "retryable": false,
     *     //   "httpStatusCode": 400
     *     // }
     *   });
     *
     * For more info, see:
     *
     * {@link https://w.amazon.com/bin/view/IdentityServices/Transitive_Authentication/Onboarding/InitiatorOnboarding/}
     * {@link https://w.amazon.com/bin/view/IdentityServices/Transitive_Authentication/Concepts/#HTransitiveAuthenticationforInternaltools2Fportals2FUI}
     * {@link https://w.amazon.com/bin/view/CDOP/DMA/DataSharing/Builder_Guidance/DMA_Data_Sharing_Schema/#HLinesofBusiness}
     * {@link https://w.amazon.com/bin/view/IdentityServices/Transitive_Authentication/Onboarding/DigitalMarketsAct/}
     * {@link https://w.amazon.com/bin/view/IdentityServices/Transitive_Authentication/Onboarding/DigitalMarketsAct/KeyPositions/}
     *
     * @param {string} requesterLobExpression (optional) The Line of Business (LOB) expression
     * @memberof window.harmony.transitiveAuth
     * @async
     */
    getTATokenForMidway: (requesterLobExpression?: string) => Promise<string>;
}
